//============================================================================== FUNCTION : Start Process & Reverse Process (updated process & reverse code)
window['budget'] = {
	process: function() {
		if(formValidate('#budgetReportFilter')) {
			showModal({
				title: 'Progress Report',
				content: `
					<span class="text-danger font-weight-bold"><span id="process_msg">Please wait until process completed</span> <span id="counter">00:00:00</span></span>
					<div class="d-none mt-2" id="status"></div>
				`,
				button: ['Close'],
			})
			budget.timelapse = setInterval(() => { $('#counter').text(moment($('#counter').text(), 'HH:mm:ss').add(1, 'seconds').format('HH:mm:ss')) }, 1000)
	
			$('#budgetReportFilter .btn').toggleSpinner()
			$.post("api/NAD_API_BUDGET_BUDGETCLOSING?process=1", {
							closingYear: $('#closingYear').val(),
							fundBudgetClosing: $('#fundBudgetClosing').val(),
							activity_group: $('#activity_group').val(),
							activity_subgroup: $('#activity_subgroup').val(),
							at_activity_code_top: $('#at_activity_code_top').val()
						}, function(res) {
							$('#budgetReportFilter .btn').toggleSpinner()
							clearInterval(budget.timelapse)
							$('#process_msg').text('Completed in')
							$('#status').removeClass('d-none').html(res.msg)
							if(res.status=='ok') {
								$('#status').removeClass('d-none').html(`
									<table class="mt-3" width="100%">
										<tr><td class="small-column text-nowrap"><b>Quarter ID</b></td> <td class="px-2"><b>:</b></td><td>${res.quarter_budget.qbu_quarter_id}</td></tr>
										<tr><td class="small-column text-nowrap"><b>Quarter Description</b></td> <td class="px-2"><b>:</b></td><td>${res.quarter_budget.qbu_description}</td></tr>
										<tr><td class="small-column text-nowrap"><b>Quarter Date</b></td> <td class="px-2"><b>:</b></td><td>${res.quarter_budget.qbu_start_date} - ${res.quarter_budget.qbu_end_date}</td></tr>
										<tr><td colspan="3" class="py-2"></td></tr>
										<tr><td class="small-column text-nowrap"><b>Structure Budget ${$('#closingYear').val()}</b></td><td class="px-2"><b>:</b></td><td>${res.structure_budget_prev}</td></tr>
										<tr><td class="small-column text-nowrap"><b>Structure Budget ${$('#closingYear').val()*1+1} New</b></td> <td class="px-2"><b>:</b></td><td>${res.structure_budget_new}</td></tr>
										<tr><td class="small-column text-nowrap"><b>Structure Budget ${$('#closingYear').val()*1+1} Existing</b></td> <td class="px-2"><b>:</b></td><td>${res.structure_budget_prev - res.structure_budget_new}</td></tr>
										<tr><td colspan="3" class="py-2"></td></tr>
										<tr><td class="small-column text-nowrap"><b>Budget ${$('#closingYear').val()*1+1} New</b></td> <td class="px-2"><b>:</b></td><td>${res.budget_new}</td></tr>
										<tr><td class="small-column text-nowrap"><b>Budget ${$('#closingYear').val()*1+1} Existing</b></td> <td class="px-2"><b>:</b></td><td>${res.structure_budget_prev - res.budget_new}</td></tr>
									</table>
								`)
							}
							else {
								$('#status').removeClass('d-none').html(res.msg)
							}
						}, 'json')
		}
	},
	reverse: function() {
		if(formValidate('#budgetReportFilter')) {
			$('#budgetReportFilter .btn').toggleSpinner()
			$.post("api/NAD_API_BUDGET_BUDGETCLOSING?reverse=1", {
				closingYear:$('#closingYear').val(),
				fundBudgetClosing: $('#fundBudgetClosing').val(),
				activity_group: $('#activity_group').val(),
				activity_subgroup: $('#activity_subgroup').val(),
				at_activity_code_top: $('#at_activity_code_top').val()
				}, function(res) {
				$('#budgetReportFilter .btn').toggleSpinner()
				showModal({content: 'Reverse success'})
			}, 'json')
		}
	}
}

