function get_elapsed_time_string(total_seconds){
	function pretty_time_string(num) {
		return ( num < 10 ? "0" : "" ) + num;
	}

	var hours		= Math.floor(total_seconds / 3600);
	total_seconds	= total_seconds % 3600;

	var minutes		= Math.floor(total_seconds / 60);
	total_seconds	= total_seconds % 60;

	var seconds 	= Math.floor(total_seconds);

	// Pad the minutes and seconds with leading zeros, if required
	hours	= pretty_time_string(hours);
	minutes	= pretty_time_string(minutes);
	seconds	= pretty_time_string(seconds);

	// Compose the string for display
	var currentTimeString = hours + ":" + minutes + ":" + seconds;

	return currentTimeString;
}

//============================================================================== FUNCTION : Start Process
jQuery(document).on('click', '#StartProcess', function(){
	
	var elapsed_seconds = 0;	
	if($('[id ^=ajaxMonitoringId]').length == 1)
		$('[id ^=ajaxMonitoringId]').remove();
	
	timer = setInterval(function() {
		elapsed_seconds = elapsed_seconds + 1;
		$('.alertTimer').text(get_elapsed_time_string(elapsed_seconds));
	}, 1000);
	
	processing('startProcess', 'Start Process');
});

//============================================================================== FUNCTION : Reverse Process
jQuery(document).on('click', '#ReverseProcess', function(){
	var elapsed_seconds = 0;
	
	if($('[id ^=ajaxMonitoringId]').length == 1)
		$('[id ^=ajaxMonitoringId]').remove();
	
	timer = setInterval(function() {
		elapsed_seconds = elapsed_seconds + 1;
		$('.alertTimer').text(get_elapsed_time_string(elapsed_seconds));
	}, 1000);
	
	processing('reverseProcess', 'Reverse Process');
});

//============================================================================== FUNCTION : Processing
function processing(mode, label){
	var mainData	= jQuery('#budgetReportFilter input, select').serializeArray();
	var data 		= [];
	var mergeData	= jQuery.merge(mainData, data);
	
	if(formValidate('#budgetReportFilter'))
	{
		jQuery.ajax({
			url: 'api_generator.php?api_name=NAD_API_BUDGET_BUDGETCLOSING&mode='+mode,
			type: 'POST',
			dataType: 'json',
			ajaxMonitoring: '<div class="text-danger font-weight-bold alertText">** Please wait until process is complete. - '+
							'<span class="text-danger font-weight-bold alertTimer"></span></div><br>'+
							'Processing Budget Closing : '+label,
			data: mergeData,
			success: function(data) {
				
				clearInterval(timer);
				if(data.status == 'ok')
				{
					//modalAlert('alert', LANG_PROCESS_SUCCESS);
					if(data.flag == 1)	modalAlert('alert', LANG_PROCESS_SUCCESS, 1);
					else				modalAlert('alert', data.msg, 1);
					
					if(mode == 'startProcess')   jQuery('#msgStartProcess').val(data.msg);//
					if(mode == 'reverseProcess') jQuery('#msgReverseProcess').val(data.msg);//
					
				}
				else
					modalAlert('alert', LANG_PROCESS_ERROR);
			},
			error : function(data) { 
				clearInterval(timer); 
			}
		});
	}
	else
		modalAlert('alert', LANG_VALIDATE_VALUEMISSING);
}

//============================================================================== FUNCTION : Modal
modalAlert = function msgModal(type, msg, extra){
	if(extra)
	{
		showModal({
			type	: type,
			content	: msg, 
			size	: "sm",
			onclick	: function(){ $('#modalAjaxMonitoring').modal('hide') }
		});	
	}
	else
	{
		showModal({
			type	: type,
			content	: msg, 
			size	: "sm"		  
		});	
	}
}
